// ── Node: Ingest Transcript File ─────────────────────────
// Reads transcript text from input and assigns account_id
// In production: connect to webhook or file trigger

const fs = require('fs');
const path = require('path');

const inputFile = $input.item.json.file_path || '/data/sample_transcript.txt';
const accountId = $input.item.json.account_id || '001';
const pipelineType = $input.item.json.pipeline || 'demo'; // 'demo' or 'onboarding'

let transcript = '';
try {
  transcript = fs.readFileSync(inputFile, 'utf8');
} catch(e) {
  transcript = $input.item.json.transcript_text || '';
}

return [{
  json: {
    account_id: accountId,
    pipeline_type: pipelineType,
    transcript: transcript,
    ingested_at: new Date().toISOString()
  }
}];

