// Parse agent spec and save to outputs folder
const fs = require('fs');
const path = require('path');

const raw = $input.item.json.candidates[0].content.parts[0].text;
const cleaned = raw.replace(/^```json\s*/,'').replace(/^```\s*/,'').replace(/\s*```$/,'').trim();

let spec;
try {
  spec = JSON.parse(cleaned);
} catch(e) {
  spec = { error: 'Parse failed', raw };
}

const accountId = $('parse-memo-node').item.json.account_id;
const version = 'v1';
const outputDir = `/data/outputs/accounts/${accountId}/${version}`;

try {
  fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(`${outputDir}/account_memo.json`, JSON.stringify($('parse-memo-node').item.json.memo, null, 2));
  fs.writeFileSync(`${outputDir}/agent_spec.json`, JSON.stringify(spec, null, 2));
} catch(e) {
  console.log('File write error:', e.message);
}

return [{
  json: {
    account_id: accountId,
    version: version,
    memo_saved: true,
    spec_saved: true,
    agent_name: spec.agent_name || 'Unknown'
  }
}];
